class BinarySearchTree:
    def __init__(self):
        self.root = None

    def insert(self, char):
        if self.root is None:
            self.root = char
        else:
            current = self.root
            while True:
                if char < current:
                    if current.left is None:
                        current.left = char
                        break
                    else:
                        current = current.left
                else:
                    if char > current:
                        if current.right is None:
                            current.right = char
                            break
                        else:
                            current = current.right
                    else:
                        break

def process_sequence(sequence):
    tree = BinarySearchTree()
    for char in sequence:
        tree.insert(char.lower())
    return tree

# Example sequence
